use serde::{Deserialize, Serialize};
use std::io::{self, Read};
use std::f64::consts::PI;

// Constants from spec
pub const NUM_LICS: usize = 15;

// realcompare implementation from realcompare_reference.rs
pub const LT: &str = "LT";
pub const EQ: &str = "EQ";
pub const GT: &str = "GT";

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

#[derive(Debug, Deserialize, Serialize, Clone, Copy)]
pub struct Point {
    pub x: f64,
    pub y: f64,
}

#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct Parameters {
    pub length1: f64,
    pub radius1: f64,
    pub epsilon: f64,
    pub area1: f64,
    pub q_pts: usize, // NPOINTS = 2..100
    pub quads: usize, // NUMQUADS = 1..3
    pub dist: f64,
    pub n_pts: usize, // NPTYPE = 3..100
    pub k_pts: usize, // POINTRANGE = 1..100
    pub a_pts: usize, // POINTRANGE = 1..100
    pub b_pts: usize, // POINTRANGE = 1..100
    pub c_pts: usize, // POINTRANGE = 1..100
    pub d_pts: usize, // POINTRANGE = 1..100
    pub e_pts: usize, // POINTRANGE = 1..100
    pub f_pts: usize, // POINTRANGE = 1..100
    pub g_pts: usize, // POINTRANGE = 1..100
    pub length2: f64,
    pub radius2: f64,
    pub area2: f64,
}

#[derive(Debug, Deserialize, Serialize, PartialEq, Eq, Clone, Copy)]
pub enum Connectors {
    #[serde(rename = "NOTUSED")]
    NotUsed,
    #[serde(rename = "ORR")]
    Orr,
    #[serde(rename = "ANDD")]
    Andd,
}

#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct Input {
    pub numpoints: usize,
    pub x: Vec<f64>,
    pub y: Vec<f64>,
    pub parameters: Parameters,
    pub lcm: Vec<Vec<Connectors>>, // CMATRIX = array[LICRANGE, LICRANGE] of CONNECTORS
    pub pum_diag: Vec<bool>, // Only diagonal elements are input
}

#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct Output {
    pub cmv: Vec<bool>,
    pub pum: Vec<Vec<bool>>,
    pub fuv: Vec<bool>,
    pub launch: bool,
}

pub struct DecideContext {
    pub numpoints: usize,
    pub points: Vec<Point>,
    pub parameters: Parameters,
    pub lcm: Vec<Vec<Connectors>>,
    pub pum_diag: Vec<bool>,
    pub cmv: Vec<bool>,
    pub pum: Vec<Vec<bool>>,
    pub fuv: Vec<bool>,
    pub launch: bool,
}

impl DecideContext {
    pub fn new(input: Input) -> Self {
        let mut points = Vec::with_capacity(input.numpoints);
        for i in 0..input.numpoints {
            points.push(Point { x: input.x[i], y: input.y[i] });
        }

        Self {
            numpoints: input.numpoints,
            points,
            parameters: input.parameters,
            lcm: input.lcm,
            pum_diag: input.pum_diag,
            cmv: vec![false; NUM_LICS],
            pum: vec![vec![false; NUM_LICS]; NUM_LICS],
            fuv: vec![false; NUM_LICS],
            launch: false,
        }
    }

    pub fn decide(&mut self) {
        // Evaluate LICs
        self.evaluate_lics();

        // Generate PUM
        self.generate_pum();

        // Generate FUV
        self.generate_fuv();

        // Make launch decision
        self.make_launch_decision();
    }

    fn evaluate_lics(&mut self) {
        // Implement each LIC here
        // self.cmv[0] = lic0_function(...);
        // ...
        self.cmv[0] = self.lic0();
        self.cmv[1] = self.lic1();
        self.cmv[2] = self.lic2();
        self.cmv[3] = self.lic3();
        self.cmv[4] = self.lic4();
        self.cmv[5] = self.lic5();
        self.cmv[6] = self.lic6();
        self.cmv[7] = self.lic7();
        self.cmv[8] = self.lic8();
        self.cmv[9] = self.lic9();
        self.cmv[10] = self.lic10();
        self.cmv[11] = self.lic11();
        self.cmv[12] = self.lic12();
        self.cmv[13] = self.lic13();
        self.cmv[14] = self.lic14();
    }

    fn lic0(&self) -> bool {
        // LIC 0: There exists at least one set of two consecutive data points that are a distance greater than the length, LENGTH1, apart.
        // Constraints: (0 <= LENGTH1)

        if self.numpoints < 2 {
            return false;
        }

        let length1 = self.parameters.length1;
        if realcompare(length1, 0.0) == LT {
            // Constraint violation, but spec says "Do not include input error checking."
            // Assuming valid input, LENGTH1 >= 0.
        }

        for i in 0..(self.numpoints - 1) {
            let p1 = self.points[i];
            let p2 = self.points[i+1];
            let dist = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
            if realcompare(dist, length1) == GT {
                return true;
            }
        }
        false
    }
    fn lic1(&self) -> bool {
        // LIC 1: There exists at least one set of three consecutive data points that cannot all be contained within or on a circle of radius RADIUS1.
        // Constraints: (0 <= RADIUS1)
        if self.numpoints < 3 {
            return false;
        }
        let radius1 = self.parameters.radius1;
        if realcompare(radius1, 0.0) == LT {
            // Constraint violation, but spec says "Do not include input error checking."
            // Assuming valid input, RADIUS1 >= 0.
        }

        for i in 0..(self.numpoints - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i+1];
            let p3 = self.points[i+2];

            // Case 1: All three points are collinear
            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, 0.0) == EQ {
                let d12 = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let d13 = ((p1.x - p3.x).powi(2) + (p1.y - p3.y).powi(2)).sqrt();
                let d23 = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();

                let max_dist = d12.max(d13).max(d23);
                if realcompare(max_dist, 2.0 * radius1) == GT {
                    return true;
                }
            } else {
                // Case 2: Points are not collinear. Calculate circumradius.
                let a = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let b = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();
                let c = ((p3.x - p1.x).powi(2) + (p3.y - p1.y).powi(2)).sqrt();

                let circumradius = (a * b * c) / (4.0 * area);

                if realcompare(circumradius, radius1) == GT {
                    return true;
                }
            }
        }
        false
    }

    fn lic2(&self) -> bool {
        // LIC 2: There exists at least one set of three consecutive data points which form an angle such that:
        // - angle < (PI - EPSILON), or
        // - angle > (PI + EPSILON)
        // The second of the three consecutive points is always the vertex of the angle. If either the first point or the last point (or both) coincides with the vertex, the angle is undefined and the LIC is not satisfied by those three points.
        // Constraints: (0 <= EPSILON < PI)

        if self.numpoints < 3 {
            return false;
        }

        let epsilon = self.parameters.epsilon;
        if realcompare(epsilon, 0.0) == LT || realcompare(epsilon, PI) != LT {
            // Constraint violation, assuming valid input.
        }

        for i in 0..(self.numpoints - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i+1]; // Vertex
            let p3 = self.points[i+2];

            // Check for coinciding points
            if (realcompare(p1.x, p2.x) == EQ && realcompare(p1.y, p2.y) == EQ) ||
               (realcompare(p3.x, p2.x) == EQ && realcompare(p3.y, p2.y) == EQ) {
                continue; // Angle is undefined
            }

            let v1_x = p1.x - p2.x;
            let v1_y = p1.y - p2.y;
            let v2_x = p3.x - p2.x;
            let v2_y = p3.y - p2.y;

            let dot_product = v1_x * v2_x + v1_y * v2_y;
            let magnitude1 = (v1_x.powi(2) + v1_y.powi(2)).sqrt();
            let magnitude2 = (v2_x.powi(2) + v2_y.powi(2)).sqrt();

            // Check if magnitudes are zero to avoid division by zero
            if realcompare(magnitude1, 0.0) == EQ || realcompare(magnitude2, 0.0) == EQ {
                continue; // Should not happen if points don't coincide with vertex, but good to be safe.
            }

            let cos_angle = dot_product / (magnitude1 * magnitude2);
            // Ensure cos_angle is within [-1, 1] for acos to be valid
            let cos_angle = cos_angle.max(-1.0).min(1.0);
            let angle = cos_angle.acos();

            if realcompare(angle, PI - epsilon) == LT || realcompare(angle, PI + epsilon) == GT {
                return true;
            }
        }
        false
    }

    fn lic3(&self) -> bool {
        // LIC 3: There exists at least one set of three consecutive data points that are the vertices of a triangle with area greater than AREA1.
        // Constraints: (0 <= AREA1)
        if self.numpoints < 3 {
            return false;
        }

        let area1 = self.parameters.area1;
        if realcompare(area1, 0.0) == LT {
            // Constraint violation, assuming valid input.
        }

        for i in 0..(self.numpoints - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i+1];
            let p3 = self.points[i+2];

            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, area1) == GT {
                return true;
            }
        }
        false
    }

    fn lic4(&self) -> bool {
        // LIC 4: There exists at least one set of Q_PTS consecutive data points that lie in more than QUADS quadrants.
        // Where there is ambiguity as to which quadrant contains a given point, priority of decision will be by quadrant number, i.e., I, II, III, IV.
        // For example, the data point (0,0) is in quadrant I, the point (-1,0) is in quadrant II, the point (0,-1) is in quadrant III,
        // the point (0,1) is in quadrant I, and the point (1,0) is in quadrant I.
        // Constraints: (2 <= Q_PTS <= NUMPOINTS), (1 <= QUADS <= 3)

        let q_pts = self.parameters.q_pts;
        let quads = self.parameters.quads;

        if self.numpoints < q_pts || q_pts < 2 || quads < 1 || quads > 3 {
            return false;
        }

        for i in 0..(self.numpoints - q_pts + 1) {
            let mut quadrants_present = [false; 4]; // Quadrant I, II, III, IV
            let mut distinct_quadrants = 0;

            for j in 0..q_pts {
                let point = self.points[i + j];
                let quad_idx = get_quadrant(point);

                if !quadrants_present[quad_idx] {
                    quadrants_present[quad_idx] = true;
                    distinct_quadrants += 1;
                }
            }

            if distinct_quadrants > quads {
                return true;
            }
        }
        false
    }

    fn lic5(&self) -> bool {
        // LIC 5: There exists at least one set of two consecutive data points, (X[i], Y[i]) and (X[j], Y[j]), such that X[j] - X[i] < 0 (where i = j - 1).
        if self.numpoints < 2 {
            return false;
        }

        for i in 0..(self.numpoints - 1) {
            let p1 = self.points[i];
            let p2 = self.points[i+1];
            if realcompare(p2.x - p1.x, 0.0) == LT {
                return true;
            }
        }
        false
    }

    fn lic6(&self) -> bool {
        // LIC 6: There exists at least one set of N_PTS consecutive data points such that at least one of the points lies a distance greater than DIST from the line joining the first and last of these N_PTS points.
        // If the first and last points of these N_PTS are identical, then the calculated distance to compare with DIST will be the distance from the coincident point to all other points of the N_PTS consecutive points.
        // The condition is not met when NUMPOINTS < 3.
        // Constraints: (3 <= N_PTS <= NUMPOINTS), (0 <= DIST)

        let n_pts = self.parameters.n_pts;
        let dist_param = self.parameters.dist;

        if self.numpoints < 3 || n_pts < 3 || n_pts > self.numpoints || realcompare(dist_param, 0.0) == LT {
            return false;
        }

        for i in 0..(self.numpoints - n_pts + 1) {
            let p_first = self.points[i];
            let p_last = self.points[i + n_pts - 1];

            if realcompare(p_first.x, p_last.x) == EQ && realcompare(p_first.y, p_last.y) == EQ {
                // First and last points are identical
                for j in 1..(n_pts - 1) {
                    let p_mid = self.points[i + j];
                    let distance = ((p_first.x - p_mid.x).powi(2) + (p_first.y - p_mid.y).powi(2)).sqrt();
                    if realcompare(distance, dist_param) == GT {
                        return true;
                    }
                }
            } else {
                // First and last points are distinct. Calculate distance from intermediate points to the line.
                // Line equation: Ax + By + C = 0
                // A = p_last.y - p_first.y
                // B = p_first.x - p_last.x
                // C = p_last.x * p_first.y - p_first.x * p_last.y
                let a = p_last.y - p_first.y;
                let b = p_first.x - p_last.x;
                let c = p_last.x * p_first.y - p_first.x * p_last.y;
                let line_denominator = (a.powi(2) + b.powi(2)).sqrt();

                if realcompare(line_denominator, 0.0) == EQ {
                    // This case implies p_first and p_last are identical, which is handled above.
                    // If not, it means the line is degenerate (points coincide).
                    // Given the check above, this path should only be taken if they are distinct.
                    // This would mean line_denominator is very close to zero due to precision.
                    // If p_first and p_last are distinct, line_denominator should be > 0.
                    // We can skip or return false as per undefined behavior or strict inequality.
                    // However, for distinct points, line_denominator should not be 0 unless
                    // the difference in x and y is exactly zero (which is handled by the identical points case).
                    continue;
                }

                for j in 1..(n_pts - 1) {
                    let p_mid = self.points[i + j];
                    let distance = (a * p_mid.x + b * p_mid.y + c).abs() / line_denominator;
                    if realcompare(distance, dist_param) == GT {
                        return true;
                    }
                }
            }
        }
        false
    }

    fn lic7(&self) -> bool {
        // LIC 7: There exists at least one set of two data points separated by exactly K_PTS consecutive intervening points that are a distance greater than the length, LENGTH1, apart.
        // The condition is not met when NUMPOINTS < 3.
        // Constraints: (1 <= K_PTS <= NUMPOINTS - 2)

        let k_pts = self.parameters.k_pts;
        let length1 = self.parameters.length1;

        if self.numpoints < 3 || k_pts < 1 || k_pts > self.numpoints - 2 || realcompare(length1, 0.0) == LT {
            return false;
        }

        for i in 0..(self.numpoints - k_pts - 1) {
            let p1 = self.points[i];
            let p2 = self.points[i + k_pts + 1];

            let dist = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
            if realcompare(dist, length1) == GT {
                return true;
            }
        }
        false
    }

    fn lic8(&self) -> bool {
        // LIC 8: There exists at least one set of three data points separated by exactly A_PTS and B_PTS consecutive intervening points, respectively, that cannot be contained within or on a circle of radius RADIUS1.
        // The condition is not met when NUMPOINTS < 5.
        // Constraints: (1 <= A_PTS), (1 <= B_PTS), A_PTS + B_PTS <= NUMPOINTS - 3

        let a_pts = self.parameters.a_pts;
        let b_pts = self.parameters.b_pts;
        let radius1 = self.parameters.radius1;

        if self.numpoints < 5 || a_pts < 1 || b_pts < 1 || a_pts + b_pts > self.numpoints - 3 || realcompare(radius1, 0.0) == LT {
            return false;
        }

        for i in 0..(self.numpoints - a_pts - b_pts - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i + a_pts + 1];
            let p3 = self.points[i + a_pts + b_pts + 2];

            // Same logic as LIC1 for checking if points can be contained in a circle.
            // Case 1: All three points are collinear
            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, 0.0) == EQ {
                let d12 = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let d13 = ((p1.x - p3.x).powi(2) + (p1.y - p3.y).powi(2)).sqrt();
                let d23 = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();

                let max_dist = d12.max(d13).max(d23);
                if realcompare(max_dist, 2.0 * radius1) == GT {
                    return true;
                }
            } else {
                // Case 2: Points are not collinear. Calculate circumradius.
                let a = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let b = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();
                let c = ((p3.x - p1.x).powi(2) + (p3.y - p1.y).powi(2)).sqrt();

                let circumradius = (a * b * c) / (4.0 * area);

                if realcompare(circumradius, radius1) == GT {
                    return true;
                }
            }
        }
        false
    }

    fn lic9(&self) -> bool {
        // LIC 9: There exists at least one set of three data points separated by exactly C_PTS and D_PTS consecutive intervening points, respectively, that form an angle such that:
        // - angle < (PI - EPSILON), or
        // - angle > (PI + EPSILON)
        // The second point of the set of three points is always the vertex of the angle. If either the first point or the last point (or both) coincide with the vertex, the angle is undefined and the LIC is not satisfied by those three points.
        // The condition is not met when NUMPOINTS < 5.
        // Constraints: (1 <= C_PTS), (1 <= D_PTS), C_PTS + D_PTS <= NUMPOINTS - 3

        let c_pts = self.parameters.c_pts;
        let d_pts = self.parameters.d_pts;
        let epsilon = self.parameters.epsilon;

        if self.numpoints < 5 || c_pts < 1 || d_pts < 1 || c_pts + d_pts > self.numpoints - 3 || realcompare(epsilon, 0.0) == LT || realcompare(epsilon, PI) != LT {
            return false;
        }

        for i in 0..(self.numpoints - c_pts - d_pts - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i + c_pts + 1]; // Vertex
            let p3 = self.points[i + c_pts + d_pts + 2];

            // Check for coinciding points
            if (realcompare(p1.x, p2.x) == EQ && realcompare(p1.y, p2.y) == EQ) ||
               (realcompare(p3.x, p2.x) == EQ && realcompare(p3.y, p2.y) == EQ) {
                continue; // Angle is undefined
            }

            let v1_x = p1.x - p2.x;
            let v1_y = p1.y - p2.y;
            let v2_x = p3.x - p2.x;
            let v2_y = p3.y - p2.y;

            let dot_product = v1_x * v2_x + v1_y * v2_y;
            let magnitude1 = (v1_x.powi(2) + v1_y.powi(2)).sqrt();
            let magnitude2 = (v2_x.powi(2) + v2_y.powi(2)).sqrt();

            if realcompare(magnitude1, 0.0) == EQ || realcompare(magnitude2, 0.0) == EQ {
                continue;
            }

            let cos_angle = dot_product / (magnitude1 * magnitude2);
            let cos_angle = cos_angle.max(-1.0).min(1.0);
            let angle = cos_angle.acos();

            if realcompare(angle, PI - epsilon) == LT || realcompare(angle, PI + epsilon) == GT {
                return true;
            }
        }
        false
    }
    fn lic10(&self) -> bool {
        // LIC 10: There exists at least one set of three data points separated by exactly E_PTS and F_PTS consecutive intervening points, respectively, that are the vertices of a triangle with area greater than AREA1.
        // The condition is not met when NUMPOINTS < 5.
        // Constraints: (1 <= E_PTS), (1 <= F_PTS), E_PTS + F_PTS <= NUMPOINTS - 3

        let e_pts = self.parameters.e_pts;
        let f_pts = self.parameters.f_pts;
        let area1 = self.parameters.area1;

        if self.numpoints < 5 || e_pts < 1 || f_pts < 1 || e_pts + f_pts > self.numpoints - 3 || realcompare(area1, 0.0) == LT {
            return false;
        }

        for i in 0..(self.numpoints - e_pts - f_pts - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i + e_pts + 1];
            let p3 = self.points[i + e_pts + f_pts + 2];

            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, area1) == GT {
                return true;
            }
        }
        false
    }

    fn lic11(&self) -> bool {
        // LIC 11: There exists at least one set of two data points, (X[i], Y[i]) and (X[j], Y[j]), separated by exactly G_PTS consecutive intervening points, such that X[j] - X[i] < 0 (where i < j).
        // The condition is not met when NUMPOINTS < 3.
        // Constraints: (1 <= G_PTS <= NUMPOINTS - 2)

        let g_pts = self.parameters.g_pts;

        if self.numpoints < 3 || g_pts < 1 || g_pts > self.numpoints - 2 {
            return false;
        }

        for i in 0..(self.numpoints - g_pts - 1) {
            let p1 = self.points[i];
            let p2 = self.points[i + g_pts + 1];
            if realcompare(p2.x - p1.x, 0.0) == LT {
                return true;
            }
        }
        false
    }

    fn lic12(&self) -> bool {
        // LIC 12: There exists at least one set of two data points, separated by exactly K_PTS consecutive intervening points, which are a distance greater than the length, LENGTH1, apart.
        // In addition, there exists at least one set of two data points (which can be the same or different from the two data points just mentioned), separated by exactly K_PTS consecutive intervening points, that are a distance less than the length, LENGTH2, apart.
        // Both parts must be true for the LIC to be true. The condition is not met when NUMPOINTS < 3.
        // Constraints: (0 <= LENGTH2)

        let k_pts = self.parameters.k_pts;
        let length1 = self.parameters.length1;
        let length2 = self.parameters.length2;

        if self.numpoints < 3 || k_pts < 1 || k_pts > self.numpoints - 2 || realcompare(length1, 0.0) == LT || realcompare(length2, 0.0) == LT {
            return false;
        }

        let mut condition1_met = false;
        for i in 0..(self.numpoints - k_pts - 1) {
            let p1 = self.points[i];
            let p2 = self.points[i + k_pts + 1];
            let dist = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
            if realcompare(dist, length1) == GT {
                condition1_met = true;
                break;
            }
        }

        let mut condition2_met = false;
        for i in 0..(self.numpoints - k_pts - 1) {
            let p1 = self.points[i];
            let p2 = self.points[i + k_pts + 1];
            let dist = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
            if realcompare(dist, length2) == LT {
                condition2_met = true;
                break;
            }
        }

        condition1_met && condition2_met
    }

    fn lic13(&self) -> bool {
        // LIC 13: There exists at least one set of three data points, separated by exactly A_PTS and B_PTS consecutive intervening points, respectively, that cannot be contained within or on a circle of radius RADIUS1.
        // In addition, there exists at least one set of three data points (which can be the same or different from the three data points just mentioned) separated by exactly A_PTS and B_PTS consecutive intervening points, respectively, that can be contained in or on a circle of radius RADIUS2.
        // Both parts must be true for the LIC to be true. The condition is not met when NUMPOINTS < 5.
        // Constraints: (0 <= RADIUS2)

        let a_pts = self.parameters.a_pts;
        let b_pts = self.parameters.b_pts;
        let radius1 = self.parameters.radius1;
        let radius2 = self.parameters.radius2;

        if self.numpoints < 5 || a_pts < 1 || b_pts < 1 || a_pts + b_pts > self.numpoints - 3 || realcompare(radius1, 0.0) == LT || realcompare(radius2, 0.0) == LT {
            return false;
        }

        let mut condition1_met = false;
        for i in 0..(self.numpoints - a_pts - b_pts - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i + a_pts + 1];
            let p3 = self.points[i + a_pts + b_pts + 2];

            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, 0.0) == EQ {
                let d12 = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let d13 = ((p1.x - p3.x).powi(2) + (p1.y - p3.y).powi(2)).sqrt();
                let d23 = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();

                let max_dist = d12.max(d13).max(d23);
                if realcompare(max_dist, 2.0 * radius1) == GT {
                    condition1_met = true;
                    break;
                }
            } else {
                let a = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let b = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();
                let c = ((p3.x - p1.x).powi(2) + (p3.y - p1.y).powi(2)).sqrt();

                let circumradius = (a * b * c) / (4.0 * area);
                if realcompare(circumradius, radius1) == GT {
                    condition1_met = true;
                    break;
                }
            }
        }

        let mut condition2_met = false;
        for i in 0..(self.numpoints - a_pts - b_pts - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i + a_pts + 1];
            let p3 = self.points[i + a_pts + b_pts + 2];

            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, 0.0) == EQ {
                let d12 = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let d13 = ((p1.x - p3.x).powi(2) + (p1.y - p3.y).powi(2)).sqrt();
                let d23 = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();

                let max_dist = d12.max(d13).max(d23);
                if realcompare(max_dist, 2.0 * radius2) != GT { // i.e. <=
                    condition2_met = true;
                    break;
                }
            } else {
                let a = ((p1.x - p2.x).powi(2) + (p1.y - p2.y).powi(2)).sqrt();
                let b = ((p2.x - p3.x).powi(2) + (p2.y - p3.y).powi(2)).sqrt();
                let c = ((p3.x - p1.x).powi(2) + (p3.y - p1.y).powi(2)).sqrt();

                let circumradius = (a * b * c) / (4.0 * area);
                if realcompare(circumradius, radius2) != GT { // i.e. <=
                    condition2_met = true;
                    break;
                }
            }
        }

        condition1_met && condition2_met
    }

    fn lic14(&self) -> bool {
        // LIC 14: There exists at least one set of three data points, separated by exactly E_PTS and F_PTS consecutive intervening points, respectively, that are the vertices of a triangle with area greater than AREA1.
        // In addition, there exist three data points (which can be the same or different from the three data points just mentioned) separated by exactly E_PTS and F_PTS consecutive intervening points, respectively, that are the vertices of a triangle with area less than AREA2.
        // Both parts must be true for the LIC to be true. The condition is not met when NUMPOINTS < 5.
        // Constraints: (0 <= AREA2)

        let e_pts = self.parameters.e_pts;
        let f_pts = self.parameters.f_pts;
        let area1 = self.parameters.area1;
        let area2 = self.parameters.area2;

        if self.numpoints < 5 || e_pts < 1 || f_pts < 1 || e_pts + f_pts > self.numpoints - 3 || realcompare(area1, 0.0) == LT || realcompare(area2, 0.0) == LT {
            return false;
        }

        let mut condition1_met = false;
        for i in 0..(self.numpoints - e_pts - f_pts - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i + e_pts + 1];
            let p3 = self.points[i + e_pts + f_pts + 2];

            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, area1) == GT {
                condition1_met = true;
                break;
            }
        }

        let mut condition2_met = false;
        for i in 0..(self.numpoints - e_pts - f_pts - 2) {
            let p1 = self.points[i];
            let p2 = self.points[i + e_pts + 1];
            let p3 = self.points[i + e_pts + f_pts + 2];

            let area = 0.5 * ((p1.x * (p2.y - p3.y)) + (p2.x * (p3.y - p1.y)) + (p3.x * (p1.y - p2.y))).abs();
            if realcompare(area, area2) == LT {
                condition2_met = true;
                break;
            }
        }

        condition1_met && condition2_met
    }

    fn generate_pum(&mut self) {
        for i in 0..NUM_LICS {
            for j in 0..NUM_LICS {
                if i == j {
                    self.pum[i][j] = self.pum_diag[i];
                } else {
                    self.pum[i][j] = match self.lcm[i][j] {
                        Connectors::NotUsed => true,
                        Connectors::Andd => self.cmv[i] && self.cmv[j],
                        Connectors::Orr => self.cmv[i] || self.cmv[j],
                    };
                }
            }
        }
    }

    fn generate_fuv(&mut self) {
        for i in 0..NUM_LICS {
            if !self.pum[i][i] {
                self.fuv[i] = true;
            } else {
                let mut all_true_in_row = true;
                for j in 0..NUM_LICS {
                    if !self.pum[i][j] {
                        all_true_in_row = false;
                        break;
                    }
                }
                self.fuv[i] = all_true_in_row;
            }
        }
    }

    fn make_launch_decision(&mut self) {
        self.launch = self.fuv.iter().all(|&x| x);
    }
}

// Helper function to determine quadrant
fn get_quadrant(p: Point) -> usize {
    // Priority: I, II, III, IV
    if realcompare(p.x, 0.0) == GT && realcompare(p.y, 0.0) == GT { // x > 0, y > 0
        0 // Quadrant I
    } else if realcompare(p.x, 0.0) == LT && realcompare(p.y, 0.0) == GT { // x < 0, y > 0
        1 // Quadrant II
    } else if realcompare(p.x, 0.0) == LT && realcompare(p.y, 0.0) == LT { // x < 0, y < 0
        2 // Quadrant III
    } else if realcompare(p.x, 0.0) == GT && realcompare(p.y, 0.0) == LT { // x > 0, y < 0
        3 // Quadrant IV
    } else if realcompare(p.x, 0.0) == EQ && realcompare(p.y, 0.0) == EQ { // (0,0)
        0 // Quadrant I
    } else if realcompare(p.x, 0.0) == LT && realcompare(p.y, 0.0) == EQ { // (-1,0)
        1 // Quadrant II
    } else if realcompare(p.x, 0.0) == EQ && realcompare(p.y, 0.0) == LT { // (0,-1)
        2 // Quadrant III
    } else if realcompare(p.x, 0.0) == EQ && realcompare(p.y, 0.0) == GT { // (0,1)
        0 // Quadrant I
    } else if realcompare(p.x, 0.0) == GT && realcompare(p.y, 0.0) == EQ { // (1,0)
        0 // Quadrant I
    } else {
        // This should cover all other cases on axes, but to be explicit,
        // points on axes or origin get assigned to I, II, III, or IV
        // based on the priority given in the spec.
        // For example, (0,1) is I, (-1,0) is II, (0,-1) is III, (1,0) is I.
        // My explicit checks above cover these specific examples.
        // Fallback for any other points on axes:
        if realcompare(p.x, 0.0) == EQ { // On Y-axis
            if realcompare(p.y, 0.0) == GT { 0 } else { 2 } // (0,y>0) is I, (0,y<0) is III
        } else { // On X-axis (realcompare(p.y, 0.0) == EQ)
            if realcompare(p.x, 0.0) == GT { 0 } else { 1 } // (x>0,0) is I, (x<0,0) is II
        }
    }
}

fn main() {
    let mut buffer = String::new();
    io::stdin().read_to_string(&mut buffer).expect("Failed to read from stdin");

    let input: Input = serde_json::from_str(&buffer).expect("Failed to parse JSON input");

    let mut context = DecideContext::new(input);
    context.decide();

    let output = Output {
        cmv: context.cmv.to_vec(),
        pum: context.pum.to_vec(),
        fuv: context.fuv.to_vec(),
        launch: context.launch,
    };

    let json_output = serde_json::to_string_pretty(&output).expect("Failed to serialize JSON output");
    println!("{}", json_output);
}
